// Parse each CSV row into a prospect object
return items.map((item, index) => {
  const row = item.json;
  return {
    json: {
      index: index + 1,
      legal_name: row.legal_name || '',
      business_email: row.business_email || '',
      phone: row.phone || '',
      website: row.website || '',
      county: row.county || '',
      employees_estimate: parseInt(row.employees_estimate) || 0,
      created_at: new Date().toISOString(),
      source: 'CSV Migration'
    }
  };
});

// Combine enriched data with scoring results
const enriched = $node['Enrich Prospect Data'].json;
const scored = $node['Score via Claude API'].json;

return [{
  json: {
    ...enriched,
    score: scored?.score || 0,
    service_fit: scored?.service_fit || 'unknown',
    segment: scored?.segment || 'Unknown',
    priority: scored?.priority || 5,
    intent_signal: scored?.intent_signal || 'low',
    icebreaker: scored?.icebreaker || '',
    pipeline_status: 'pending_review',
    import_batch: $node['Manual Trigger'].executionData.startData.timestamp,
    scored_at: new Date().toISOString()
  }
}];
